module RefModule(input  a,
                  input  b,
                  input  in_carry,
                  output sum,
                  output carry);wire obf_sum0;
    wire carry0;
    wire carry1;

    xor (obf_sum0, a, b);
    and (carry0, a, b);

    xor (sum, obf_sum0, in_carry);
    and (carry1, obf_sum0, in_carry);

    xor (carry, carry0, carry1);

endmodule
